import{t as e}from"./hero-slide-1-BX20VcK-.js";var t=`/assets/hero-slide-2-BxSqESOf.webp`,n=e,r=[{id:`fallback-1`,slug:`logistics-xanh-tuong-lai-ben-vung`,category:`Xu Hướng`,title:`Logistics xanh: Tương lai bền vững cho ngành vận tải Việt Nam`,excerpt:`Giảm phát thải carbon và chuyển đổi sang phương tiện sạch đang định hình lại ngành logistics toàn cầu.`,content:`## Logistics xanh không còn là lựa chọn xa vời
Các doanh nghiệp vận tải đang từng bước tối ưu hành trình, giảm quãng đường rỗng và sử dụng phương tiện tiết kiệm nhiên liệu.

## Công nghệ tạo nên khác biệt
Hệ thống quản lý vận tải và dữ liệu thời gian thực giúp doanh nghiệp theo dõi mức tiêu hao, chủ động ghép chuyến và hạn chế phát thải.

**Việt Hương Logistics hướng tới những hành trình hiệu quả hơn cho khách hàng và thân thiện hơn với môi trường.**`,published_at:`2025-05-20T08:00:00.000Z`,thumbnail_url:e},{id:`fallback-2`,slug:`ai-va-du-lieu-lon-toi-uu-van-tai`,category:`Công Nghệ`,title:`AI và dữ liệu lớn trong tối ưu hóa tuyến đường vận tải`,excerpt:`Dữ liệu và trí tuệ nhân tạo giúp dự báo nhu cầu, tối ưu tuyến đường và nâng cao khả năng giao hàng đúng hẹn.`,content:`## Dữ liệu trở thành lợi thế vận hành
Thông tin về đơn hàng, mật độ giao thông và năng lực đội xe có thể được tổng hợp để lựa chọn hành trình phù hợp hơn.

## Từ phản ứng sang dự báo
Các mô hình phân tích hỗ trợ doanh nghiệp nhận biết nguy cơ chậm trễ sớm, từ đó điều phối phương tiện và tài xế chủ động.

**Giá trị lớn nhất của AI nằm ở khả năng hỗ trợ con người đưa ra quyết định nhanh và chính xác hơn.**`,published_at:`2025-05-14T08:00:00.000Z`,thumbnail_url:t},{id:`fallback-3`,slug:`viet-huong-mo-trung-tam-phan-phoi-mien-bac`,category:`Tin Tức`,title:`Việt Hương mở rộng mạng lưới phân phối tại miền Bắc`,excerpt:`Mạng lưới kho bãi và vận tải được mở rộng nhằm đáp ứng nhu cầu giao nhận ngày càng cao của doanh nghiệp.`,content:`## Tăng năng lực kết nối liên vùng
Việc mở rộng điểm trung chuyển giúp rút ngắn khoảng cách từ kho đến khách hàng và cải thiện thời gian xử lý đơn.

## Đồng bộ chất lượng dịch vụ
Quy trình vận hành, theo dõi hàng hóa và tiêu chuẩn an toàn được áp dụng thống nhất trên toàn hệ thống.

**Mục tiêu của Việt Hương là mang đến trải nghiệm giao nhận ổn định ở mọi khu vực.**`,published_at:`2025-05-08T08:00:00.000Z`,thumbnail_url:e},{id:`fallback-4`,slug:`chuoi-cung-ung-dong-nam-a-co-hoi-vang`,category:`Phân Tích`,title:`Chuỗi cung ứng Đông Nam Á: Cơ hội cho logistics Việt`,excerpt:`Sự dịch chuyển sản xuất trong khu vực mở ra cơ hội mới cho các doanh nghiệp logistics có năng lực kết nối linh hoạt.`,content:`## Một thị trường đang chuyển động nhanh
Hoạt động sản xuất và thương mại nội khối tăng lên kéo theo nhu cầu vận tải xuyên biên giới, kho bãi và thủ tục hải quan.

## Lợi thế của doanh nghiệp Việt
Vị trí địa lý, mạng lưới đường bộ và kinh nghiệm vận hành nội địa tạo nền tảng tốt để kết nối với các thị trường lân cận.

**Doanh nghiệp chuẩn hóa quy trình sớm sẽ có lợi thế khi chuỗi cung ứng khu vực tiếp tục mở rộng.**`,published_at:`2025-05-02T08:00:00.000Z`,thumbnail_url:t},{id:`fallback-5`,slug:`viet-huong-logistics-world-expo-2025`,category:`Sự Kiện`,title:`Việt Hương tham dự Logistics World Expo 2025`,excerpt:`Sự kiện là dịp kết nối đối tác, cập nhật công nghệ và tìm kiếm giải pháp mới cho chuỗi cung ứng.`,content:`## Kết nối cộng đồng logistics
Triển lãm quy tụ doanh nghiệp vận tải, kho bãi, công nghệ và thương mại từ nhiều thị trường trong khu vực.

## Mang kinh nghiệm về hoạt động thực tế
Những xu hướng mới về tự động hóa, vận tải xanh và quản trị dữ liệu sẽ được nghiên cứu để áp dụng phù hợp tại Việt Nam.

**Việt Hương Logistics luôn chủ động học hỏi để nâng cao chất lượng phục vụ khách hàng.**`,published_at:`2025-04-25T08:00:00.000Z`,thumbnail_url:e}];function i(e){return!e||e===`Tất Cả`?r:r.filter(t=>t.category===e)}function a(e){return r.find(t=>String(t.id)===String(e)||t.slug===e)}function o(e,t=3){return r.filter(t=>t.id!==e).slice(0,t)}export{o as a,i,r as n,a as r,n as t};